import React, { useState } from 'react';
import { TextField, Button, Container, Typography, Box } from '@mui/material';
import Layout from '../components/Layout';

const SmsConfirmationScreen: React.FC = () => {
    const [codes, setCodes] = useState<string[]>(Array(6).fill(''));
    const inputRefs: React.RefObject<HTMLInputElement>[] = Array(6)
        .fill(0)
        .map(() => React.createRef());

    const handleInputChange = (index: number, value: string) => {
        const updatedCodes = [...codes];
        updatedCodes[index] = value.toUpperCase();
        setCodes(updatedCodes);

        // Move to the next input
        if (index < 5 && value !== '') {
            inputRefs[index + 1].current?.focus();
        }
    };

    const handleInputBackspace = (index: number, value: string) => {
        const updatedCodes = [...codes];

        if (index > 0 && value === '') {
            updatedCodes[index - 1] = '';
            setCodes(updatedCodes);

            // Move back to the previous input
            inputRefs[index - 1].current?.focus();
        }
    };

    return (
        <Layout>
            <Container maxWidth="sm">
                <Box mt={5} mb={5}>
                    <Typography variant="h4" align="center" gutterBottom>
                        Confirmação de E-mail
                    </Typography>
                    <form>
                        <div style={{ display: 'flex', gap: 16 }}>
                            {codes.map((code, index) => (
                                <TextField
                                    key={index}
                                    inputRef={inputRefs[index]}
                                    autoFocus={index === 0}
                                    autoComplete="one-time-code"
                                    variant="outlined"
                                    margin="normal"
                                    fullWidth
                                    type="text"
                                    inputProps={{
                                        maxLength: 1,
                                        style: { textTransform: 'uppercase', width: '2em' },
                                    }}
                                    value={code}
                                    onChange={(e) => handleInputChange(index, e.target.value)}
                                    onKeyDown={(e) => {
                                        if (e.key === 'Backspace') {
                                            handleInputBackspace(index, codes[index]);
                                        }
                                    }}
                                />
                            ))}
                        </div>
                        <Button variant="contained" color="primary" fullWidth>
                            Verificar Código
                        </Button>
                    </form>
                </Box>
            </Container>
        </Layout>
    );
};

export default SmsConfirmationScreen;